<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  html, body {
    width: 100%;
    height: 100%;
    overflow: hidden;
    font-family: "Ubuntu", "Segoe UI", system-ui, sans-serif;
    background: #300a24;
  }

  #desktop {
    position: relative;
    width: 100vw;
    height: 100vh;
    background:
      radial-gradient(ellipse at 20% 50%, rgba(233, 84, 32, 0.18) 0%, transparent 50%),
      radial-gradient(ellipse at 80% 20%, rgba(119, 33, 111, 0.35) 0%, transparent 45%),
      linear-gradient(160deg, #2c001e 0%, #4a1030 40%, #300a24 70%, #1a0514 100%);
    overflow: hidden;
    user-select: none;
  }

  /* Top panel (Ubuntu-style) */
  #top-panel {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 28px;
    background: rgba(0, 0, 0, 0.72);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    color: #eee;
    font-size: 13px;
    z-index: 9000;
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }
  #top-panel .activities { font-weight: 600; letter-spacing: 0.3px; }
  #top-panel .clock { opacity: 0.9; }

  /* Dock / taskbar */
  #taskbar {
    position: absolute;
    left: 50%;
    bottom: 12px;
    transform: translateX(-50%);
    display: flex;
    gap: 8px;
    padding: 8px 12px;
    background: rgba(0, 0, 0, 0.55);
    border: 1px solid rgba(255,255,255,0.1);
    border-radius: 16px;
    backdrop-filter: blur(12px);
    z-index: 9000;
    box-shadow: 0 8px 32px rgba(0,0,0,0.45);
  }

  #taskbar button {
    width: 52px;
    height: 52px;
    border: none;
    border-radius: 12px;
    cursor: pointer;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 2px;
    font-size: 11px;
    color: #f0f0f0;
    background: rgba(255,255,255,0.08);
    transition: background 0.15s, transform 0.12s;
  }
  #taskbar button:hover {
    background: rgba(233, 84, 32, 0.55);
    transform: translateY(-3px);
  }
  #taskbar button:active { transform: translateY(0); }
  #taskbar button .icon { font-size: 22px; line-height: 1; }

  /* Windows */
  .window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    width: 560px;
    height: 400px;
    background: #2b2b2b;
    border-radius: 10px;
    border: 1px solid rgba(255,255,255,0.12);
    box-shadow: 0 16px 48px rgba(0,0,0,0.55), 0 0 0 1px rgba(0,0,0,0.3);
    display: none;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
  }
  .window.visible {
    display: flex;
  }

  .win-titlebar {
    height: 38px;
    background: linear-gradient(180deg, #3d3d3d 0%, #2f2f2f 100%);
    display: flex;
    align-items: center;
    padding: 0 10px;
    gap: 8px;
    cursor: default;
    border-bottom: 1px solid rgba(0,0,0,0.35);
    flex-shrink: 0;
  }
  .win-controls {
    display: flex;
    gap: 7px;
    margin-right: 6px;
  }
  .win-btn {
    width: 14px;
    height: 14px;
    border-radius: 50%;
    border: none;
    cursor: pointer;
    padding: 0;
  }
  .win-close { background: #e95420; }
  .win-close:hover { background: #ff6b3d; }
  .win-min { background: #eda711; pointer-events: none; }
  .win-max { background: #3eb34f; pointer-events: none; }
  .win-title {
    flex: 1;
    color: #e8e8e8;
    font-size: 13px;
    font-weight: 500;
    text-align: center;
    margin-right: 48px;
  }

  .win-body {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    background: #242424;
    min-height: 200px;
  }

  /* Files app */
  #files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 10px;
    background: #2e2e2e;
    border-bottom: 1px solid rgba(0,0,0,0.3);
    flex-shrink: 0;
  }
  #files-up {
    background: #3a3a3a;
    border: 1px solid #555;
    color: #eee;
    border-radius: 6px;
    padding: 5px 12px;
    cursor: pointer;
    font-size: 13px;
  }
  #files-up:hover { background: #4a4a4a; }
  #files-path {
    flex: 1;
    background: #1e1e1e;
    border: 1px solid #444;
    border-radius: 6px;
    color: #ddd;
    padding: 6px 10px;
    font-size: 13px;
    font-family: "Ubuntu Mono", "Consolas", monospace;
    overflow: hidden;
    white-space: nowrap;
    text-overflow: ellipsis;
  }
  #files-listing {
    flex: 1;
    overflow: auto;
    padding: 12px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
    gap: 8px;
    align-content: start;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 6px;
    padding: 10px 6px;
    border-radius: 8px;
    color: #e0e0e0;
    font-size: 12px;
    cursor: pointer;
    text-align: center;
    word-break: break-all;
    border: 1px solid transparent;
  }
  .fs-item:hover {
    background: rgba(233, 84, 32, 0.18);
    border-color: rgba(233, 84, 32, 0.35);
  }
  .fs-item.selected {
    background: rgba(233, 84, 32, 0.3);
    border-color: rgba(233, 84, 32, 0.55);
  }
  .fs-item .fs-icon {
    font-size: 32px;
    line-height: 1;
  }

  /* Notepad app */
  #notepad-toolbar {
    display: flex;
    align-items: stretch;
    background: #2e2e2e;
    border-bottom: 1px solid rgba(0,0,0,0.3);
    flex-shrink: 0;
    min-height: 36px;
  }
  #tabs {
    display: flex;
    flex: 1;
    overflow-x: auto;
    gap: 2px;
    padding: 4px 4px 0;
  }
  .tab {
    padding: 6px 14px;
    background: #3a3a3a;
    color: #ccc;
    font-size: 12px;
    border-radius: 6px 6px 0 0;
    cursor: pointer;
    white-space: nowrap;
    border: 1px solid #444;
    border-bottom: none;
    max-width: 140px;
    overflow: hidden;
    text-overflow: ellipsis;
    position: relative;
  }
  .tab:hover { background: #454545; color: #fff; }
  .tab.active {
    background: #242424;
    color: #fff;
    border-color: #555;
  }
  .tab .tab-close {
    margin-left: 8px;
    opacity: 0.6;
    font-size: 11px;
  }
  .tab .tab-close:hover { opacity: 1; color: #e95420; }
  #new-tab {
    background: transparent;
    border: none;
    color: #ccc;
    font-size: 18px;
    padding: 0 12px;
    cursor: pointer;
    flex-shrink: 0;
  }
  #new-tab:hover { color: #fff; background: rgba(255,255,255,0.06); }
  #editor {
    flex: 1;
    width: 100%;
    min-height: 200px;
    border: none;
    outline: none;
    resize: none;
    background: #1e1e1e;
    color: #e8e8e8;
    font-family: "Ubuntu Mono", "Consolas", "Courier New", monospace;
    font-size: 14px;
    line-height: 1.55;
    padding: 12px 14px;
    tab-size: 4;
  }

  /* Desktop icons (decorative) */
  .desk-icons {
    position: absolute;
    top: 48px;
    left: 16px;
    display: flex;
    flex-direction: column;
    gap: 16px;
    z-index: 1;
  }
  .desk-icon {
    display: flex;
    flex-direction: column;
    align-items: center;
    width: 72px;
    color: #f5f5f5;
    font-size: 11px;
    text-shadow: 0 1px 3px rgba(0,0,0,0.8);
    gap: 4px;
    padding: 6px;
    border-radius: 6px;
    cursor: default;
  }
  .desk-icon .di { font-size: 36px; }
</style>
</head>
<body>
<div id="desktop">
  <div id="top-panel">
    <span class="activities">Activities</span>
    <span class="clock" id="clock"></span>
  </div>

  <div class="desk-icons">
    <div class="desk-icon"><span class="di">🗂</span><span>Home</span></div>
    <div class="desk-icon"><span class="di">🗑</span><span>Trash</span></div>
  </div>

  <!-- Files window -->
  <div id="files-window" class="window" style="top: 60px; left: 80px; width: 580px; height: 420px;">
    <div class="win-titlebar" data-drag="files-window">
      <div class="win-controls">
        <button class="win-btn win-close" type="button" title="Close"></button>
        <button class="win-btn win-min" type="button" title="Minimize"></button>
        <button class="win-btn win-max" type="button" title="Maximize"></button>
      </div>
      <div class="win-title">Files</div>
    </div>
    <div class="win-body">
      <div id="files-toolbar">
        <button id="files-up" type="button">↑ Up</button>
        <div id="files-path">/</div>
      </div>
      <div id="files-listing"></div>
    </div>
  </div>

  <!-- Notepad window -->
  <div id="notepad-window" class="window" style="top: 90px; left: 200px; width: 560px; height: 400px;">
    <div class="win-titlebar" data-drag="notepad-window">
      <div class="win-controls">
        <button class="win-btn win-close" type="button" title="Close"></button>
        <button class="win-btn win-min" type="button" title="Minimize"></button>
        <button class="win-btn win-max" type="button" title="Maximize"></button>
      </div>
      <div class="win-title">Notepad</div>
    </div>
    <div class="win-body">
      <div id="notepad-toolbar">
        <div id="tabs"></div>
        <button id="new-tab" type="button" title="New tab">+</button>
      </div>
      <textarea id="editor" spellcheck="false"></textarea>
    </div>
  </div>

  <div id="taskbar">
    <button id="open-files" type="button" title="Files">
      <span class="icon">📁</span>
      <span>Files</span>
    </button>
    <button id="open-notepad" type="button" title="Notepad">
      <span class="icon">📝</span>
      <span>Notepad</span>
    </button>
  </div>
</div>

<script>
(function () {
  "use strict";

  /* ---------- Clock ---------- */
  function updateClock() {
    const el = document.getElementById("clock");
    const d = new Date();
    const opts = { weekday: "short", hour: "2-digit", minute: "2-digit" };
    el.textContent = d.toLocaleString(undefined, opts);
  }
  updateClock();
  setInterval(updateClock, 15000);

  /* ---------- Window helpers ---------- */
  let zCounter = 100;

  function showWindow(id) {
    const win = document.getElementById(id);
    win.classList.add("visible");
    win.style.display = "flex";
    zCounter += 1;
    win.style.zIndex = zCounter;
  }

  function hideWindow(win) {
    win.classList.remove("visible");
    win.style.display = "none";
  }

  document.querySelectorAll(".window").forEach(function (win) {
    const closeBtn = win.querySelector(".win-close");
    closeBtn.addEventListener("click", function (e) {
      e.stopPropagation();
      hideWindow(win);
    });
    win.addEventListener("mousedown", function () {
      zCounter += 1;
      win.style.zIndex = zCounter;
    });
  });

  document.getElementById("open-files").addEventListener("click", function () {
    showWindow("files-window");
  });
  document.getElementById("open-notepad").addEventListener("click", function () {
    showWindow("notepad-window");
  });

  /* ---------- Dragging ---------- */
  (function enableDrag() {
    let dragging = null;
    let startX, startY, origLeft, origTop;

    document.querySelectorAll(".win-titlebar").forEach(function (bar) {
      bar.addEventListener("mousedown", function (e) {
        if (e.target.closest(".win-btn")) return;
        const id = bar.getAttribute("data-drag");
        const win = document.getElementById(id);
        dragging = win;
        startX = e.clientX;
        startY = e.clientY;
        const rect = win.getBoundingClientRect();
        origLeft = rect.left;
        origTop = rect.top;
        zCounter += 1;
        win.style.zIndex = zCounter;
        e.preventDefault();
      });
    });

    document.addEventListener("mousemove", function (e) {
      if (!dragging) return;
      const dx = e.clientX - startX;
      const dy = e.clientY - startY;
      dragging.style.left = Math.max(0, origLeft + dx) + "px";
      dragging.style.top = Math.max(28, origTop + dy) + "px";
    });

    document.addEventListener("mouseup", function () {
      dragging = null;
    });
  })();

  /* ---------- Filesystem ---------- */
  const FS = {
    "/": { type: "dir", children: ["bin", "etc", "home", "usr", "var", "tmp", "opt"] },
    "/bin": { type: "dir", children: ["bash", "ls", "cat", "grep", "cp", "mv"] },
    "/etc": { type: "dir", children: ["passwd", "hosts", "fstab", "hostname", "os-release"] },
    "/home": { type: "dir", children: ["user"] },
    "/home/user": { type: "dir", children: ["Documents", "Downloads", "Pictures", ".bashrc", "readme.txt"] },
    "/home/user/Documents": { type: "dir", children: ["notes.txt", "report.md", "todo.txt"] },
    "/home/user/Downloads": { type: "dir", children: ["package.tar.gz", "image.png"] },
    "/home/user/Pictures": { type: "dir", children: ["vacation.jpg", "screenshot.png", "wallpaper.svg"] },
    "/usr": { type: "dir", children: ["bin", "lib", "share", "local"] },
    "/usr/bin": { type: "dir", children: ["python3", "node", "git"] },
    "/usr/lib": { type: "dir", children: ["modules"] },
    "/usr/share": { type: "dir", children: ["doc", "icons"] },
    "/usr/local": { type: "dir", children: ["bin"] },
    "/var": { type: "dir", children: ["log", "tmp", "cache"] },
    "/var/log": { type: "dir", children: ["syslog", "auth.log"] },
    "/var/tmp": { type: "dir", children: [] },
    "/var/cache": { type: "dir", children: ["apt"] },
    "/tmp": { type: "dir", children: [] },
    "/opt": { type: "dir", children: [] }
  };

  /* Mark files (leaf names that are not dirs under a path) */
  function isDir(path) {
    return FS[path] && FS[path].type === "dir";
  }

  function joinPath(base, name) {
    if (base === "/") return "/" + name;
    return base + "/" + name;
  }

  function parentPath(path) {
    if (path === "/") return "/";
    const parts = path.split("/").filter(Boolean);
    parts.pop();
    return parts.length ? "/" + parts.join("/") : "/";
  }

  let currentPath = "/";

  function renderListing() {
    const pathEl = document.getElementById("files-path");
    const listing = document.getElementById("files-listing");
    pathEl.textContent = currentPath;

    listing.innerHTML = "";
    const node = FS[currentPath];
    if (!node || node.type !== "dir") {
      listing.innerHTML = '<div style="color:#999;padding:20px;">Empty or unavailable</div>';
      return;
    }

    const children = node.children.slice().sort(function (a, b) {
      const pa = joinPath(currentPath, a);
      const pb = joinPath(currentPath, b);
      const da = isDir(pa) ? 0 : 1;
      const db = isDir(pb) ? 0 : 1;
      if (da !== db) return da - db;
      return a.localeCompare(b);
    });

    children.forEach(function (name) {
      const full = joinPath(currentPath, name);
      const dir = isDir(full);
      const item = document.createElement("div");
      item.className = "fs-item";
      item.dataset.name = name;
      item.dataset.path = full;
      item.dataset.dir = dir ? "1" : "0";
      item.innerHTML =
        '<span class="fs-icon">' + (dir ? "📁" : "📄") + "</span>" +
        "<span>" + name + "</span>";

      item.addEventListener("click", function () {
        listing.querySelectorAll(".fs-item").forEach(function (el) {
          el.classList.remove("selected");
        });
        item.classList.add("selected");
      });

      item.addEventListener("dblclick", function () {
        if (dir) {
          currentPath = full;
          renderListing();
        }
      });

      listing.appendChild(item);
    });
  }

  document.getElementById("files-up").addEventListener("click", function () {
    if (currentPath === "/") return;
    currentPath = parentPath(currentPath);
    renderListing();
  });

  renderListing();

  /* ---------- Notepad (tabs + localStorage) ---------- */
  const STORAGE_KEY = "ubuntu-notepad-tabs-v1";
  let tabs = [];
  let activeId = null;
  let tabSeq = 1;

  function loadTabs() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        const data = JSON.parse(raw);
        if (data && Array.isArray(data.tabs) && data.tabs.length) {
          tabs = data.tabs;
          activeId = data.activeId;
          tabSeq = data.tabSeq || (tabs.length + 1);
          if (!tabs.some(function (t) { return t.id === activeId; })) {
            activeId = tabs[0].id;
          }
          return;
        }
      }
    } catch (e) { /* ignore */ }
    tabs = [{ id: 1, title: "Untitled 1", content: "" }];
    activeId = 1;
    tabSeq = 2;
  }

  function saveTabs() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify({
        tabs: tabs,
        activeId: activeId,
        tabSeq: tabSeq
      }));
    } catch (e) { /* ignore quota */ }
  }

  function getActiveTab() {
    return tabs.find(function (t) { return t.id === activeId; }) || null;
  }

  function renderTabs() {
    const strip = document.getElementById("tabs");
    const editor = document.getElementById("editor");
    strip.innerHTML = "";

    tabs.forEach(function (tab) {
      const el = document.createElement("div");
      el.className = "tab" + (tab.id === activeId ? " active" : "");
      el.dataset.id = String(tab.id);

      const label = document.createElement("span");
      label.className = "tab-label";
      label.textContent = tab.title;
      el.appendChild(label);

      const close = document.createElement("span");
      close.className = "tab-close";
      close.textContent = "×";
      close.title = "Close tab";
      close.addEventListener("click", function (e) {
        e.stopPropagation();
        closeTab(tab.id);
      });
      el.appendChild(close);

      el.addEventListener("click", function () {
        switchTab(tab.id);
      });

      strip.appendChild(el);
    });

    const active = getActiveTab();
    if (active) {
      editor.value = active.content;
      editor.disabled = false;
    } else {
      editor.value = "";
      editor.disabled = true;
    }
  }

  function switchTab(id) {
    const editor = document.getElementById("editor");
    const current = getActiveTab();
    if (current) {
      current.content = editor.value;
    }
    activeId = id;
    saveTabs();
    renderTabs();
  }

  function closeTab(id) {
    const editor = document.getElementById("editor");
    const current = getActiveTab();
    if (current) current.content = editor.value;

    const idx = tabs.findIndex(function (t) { return t.id === id; });
    if (idx === -1) return;
    tabs.splice(idx, 1);

    if (tabs.length === 0) {
      const newTab = { id: tabSeq++, title: "Untitled 1", content: "" };
      tabs.push(newTab);
      activeId = newTab.id;
    } else if (activeId === id) {
      activeId = tabs[Math.max(0, idx - 1)].id;
    }
    saveTabs();
    renderTabs();
  }

  document.getElementById("new-tab").addEventListener("click", function () {
    const editor = document.getElementById("editor");
    const current = getActiveTab();
    if (current) current.content = editor.value;

    const n = tabs.length + 1;
    const tab = { id: tabSeq++, title: "Untitled " + n, content: "" };
    tabs.push(tab);
    activeId = tab.id;
    saveTabs();
    renderTabs();
    editor.focus();
  });

  document.getElementById("editor").addEventListener("input", function () {
    const active = getActiveTab();
    if (active) {
      active.content = this.value;
      saveTabs();
    }
  });

  /* Persist on hide / before unload */
  window.addEventListener("beforeunload", function () {
    const editor = document.getElementById("editor");
    const active = getActiveTab();
    if (active) active.content = editor.value;
    saveTabs();
  });

  loadTabs();
  renderTabs();
})();
</script>
</body>
</html>
